mapper.insert:
INSERT INTO SCHEDULE_POLL_CANDIDATE ( CANDIDATE_ID
                                    , POLL_ID
                                    , START_DT
                                    , END_DT
                                    , REGIST_DT
                                    , REGIST_ID)
VALUES ( #{candidateId, jdbcType=VARCHAR}
       , #{pollId,      jdbcType=VARCHAR}
       , #{startDt,     jdbcType=VARCHAR}
       , #{endDt,       jdbcType=VARCHAR}
       , NOW()
       , #{registId,    jdbcType=VARCHAR})

mapper.select:
SELECT COUNT(*) > 0
FROM SCHEDULE_POLL_VOTE
WHERE CANDIDATE_ID = #{candidateId, jdbcType=VARCHAR}
  AND USER_ID = #{userId, jdbcType=VARCHAR}

mapper.insert:
INSERT INTO SCHEDULE_POLL_VOTE ( VOTE_ID
                               , CANDIDATE_ID
                               , USER_ID
                               , REGIST_DT)
VALUES ( #{voteId,      jdbcType=VARCHAR}
       , #{candidateId, jdbcType=VARCHAR}
       , #{userId,      jdbcType=VARCHAR}
       , NOW())

mapper.delete:
DELETE FROM SCHEDULE_POLL_VOTE
WHERE CANDIDATE_ID = #{candidateId, jdbcType=VARCHAR}
  AND USER_ID = #{userId, jdbcType=VARCHAR}

